_USED = {}


def _next(chat_id, kind, questions):
    key = (chat_id, kind)
    used = _USED.setdefault(key, set())
    available = [question for question in questions if question not in used]
    if not available:
        used.clear()
        available = list(questions)
    question = random.SystemRandom().choice(available)
    used.add(question)
    return question


def start_new_game(chat_id):
    """تاریخچهٔ همین گروه را برای شروع بازی جدید پاک می‌کند."""
    _USED.pop((chat_id, "jorat"), None)
    _USED.pop((chat_id, "haghighat"), None)


def get_jorat(chat_id=None):
    return _next(chat_id, "jorat", JORAT) if chat_id is not None else random.SystemRandom().choice(JORAT)


def get_haghighat(chat_id=None):
    return _next(chat_id, "haghighat", HAGHIGHAT) if chat_id is not None else random.SystemRandom().choice(HAGHIGHAT)
